head.script:
/**
 * 조직도 검색 화면 초기화 작업을 수행한다.
 * @param
 * @return
 */
scwin.popupParam;
scwin.initScreen = function() {
	scwin.popupParam=comLib.getPopupParam($p,["topDeptCd", "selectedDeptCd", "defaultDeptYn", "multiCheckYn", "orgchtDp", "searchUsrNm"]);
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, scwin.popupParam.popupID);
	if (scwin.popupParam.orgchtDp == null || scwin.popupParam.orgchtDp == "") {
		scwin.popupParam.orgchtDp = "999";
	}
	// TreeView / GridView 높이 초기화
	window.addEventListener("resize", scwin.initComponentSize, false);
	scwin.initComponentSize();

	// 다건 선택 가능시 checkbox 컬럼 보여주기
	if (scwin.popupParam.multiCheckYn == "Y") {
		grdUsrList.setColumnVisible(0, true);
	}

	// 부서코드 조회
	scwin.setDeptCd();
};

/**
 * TreeView / GridView 높이 초기화
 * @param
 * @return
 */
scwin.initComponentSize = function() {
	var componentSize = innerHeight - 205;
	trvDeptCd.setStyle("height", componentSize + "px");
	grdUsrList.setStyle("height", componentSize + "px");
}

/**
 * 부서코드 조회
 * @param
 * @return
 */
scwin.setDeptCd = function() {
	var requestData = {};
	requestData.topDeptCd = scwin.popupParam.topDeptCd; // 최상위부서
	requestData.orgchtDp = scwin.popupParam.orgchtDp; // 조직도 Depth

	var option = {action : "sc/searchmng/retrieveDeptTree.do",
		reqData : requestData,
		resData : dltDeptCd,
		success : "scwin.initCallback",
		isShowMeg : false};
	ajaxLib.executeAjax($p, option);
};

scwin.initCallback = function() {
	if (scwin.popupParam.searchUsrNm != null && scwin.popupParam.searchUsrNm != "") {
		sbxSearchGb.setValue("usrNm");
		ibxSearchTxt.setValue(scwin.popupParam.searchUsrNm);
		scwin.btnSearch_onclick();
	} else {
		// 파라미터를 통한 부서 자동선택
		if (scwin.popupParam.selectedDeptCd != null && scwin.popupParam.selectedDeptCd != "") {
			trvDeptCd.findNodeByValue(scwin.popupParam.selectedDeptCd, true);
			scwin.trvDeptInfo_onlabelclick(scwin.popupParam.selectedDeptCd, null, scwin.popupParam.selectedDeptCd);
		} else {
			// 로그인한 사용자 부서 자동 선택
			if (scwin.popupParam.defaultDeptYn == "Y") {
				var currentUsrDeptCd  = "";
				if (scwin.popupParam.orgchtDp >= 5) {
					comLib.getUsrTeamCd();
				}
				if (scwin.popupParam.orgchtDp >= 4 && (currentUsrDeptCd == null || currentUsrDeptCd == "")) {
					currentUsrDeptCd = comLib.getUsrSectCd();
				}
				if (scwin.popupParam.orgchtDp >= 3 && (currentUsrDeptCd == null || currentUsrDeptCd == "")) {
					currentUsrDeptCd = comLib.getUsrDeptCd();
				}
				if (scwin.popupParam.orgchtDp >= 2 && (currentUsrDeptCd == null || currentUsrDeptCd == "")) {
					currentUsrDeptCd = comLib.getUsrHqCd();
				}
				trvDeptCd.findNodeByValue(currentUsrDeptCd, true);
				scwin.trvDeptInfo_onlabelclick(currentUsrDeptCd, null, currentUsrDeptCd);
			}
		}
	}
}

/**
 * 사용자 정보를 조회한다.
 * @param
 * @return
 */
scwin.searchUsrList = function() {
	var requestData = {};
	requestData.dmaSearchParam = dmaSearchParam.getJSON();

	var option = {action : "sc/searchmng/retrieveUsrList.do",
		reqData : requestData,
		resData : dltUsrList,
		success : "scwin.retrieveCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
}

/**
 * 조회 버튼 클릭 시 조회조건을 기준으로 사용자를 조회한다.
 * @param
 * @return
 */
scwin.btnSearch_onclick = function() {
	var searchTxt = utilLib.trim(ibxSearchTxt.getValue());
	if (searchTxt != "") {
		// 조회조건 DataCollection 초기화
		dmaSearchParam.undo();

		// 최상위부서 세팅
		dmaSearchParam.set("topDeptCd", scwin.popupParam.topDeptCd);
		// 조직도 Depth 세팅
		dmaSearchParam.set("orgchtDp", scwin.popupParam.orgchtDp);

		// 조회조건에 맞게 데이터 세팅
		if (searchTxt != "") {
			var searchGb = sbxSearchGb.getValue();
			dmaSearchParam.set(searchGb, searchTxt);
		}

		// 조회
		scwin.searchUsrList();
	} else {
		// 검색어을(를) 입력하세요
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00147", "검색어"));
	}
};

/**
 * 사용자 정보를 조회 후 콜백 로직을 수행한다.
 * @param <Object> resBody
 * @return
 */
scwin.retrieveCallback = function(resBody) {
	txtCnt.setValue( dltUsrList.getRowCount() );
};

/**
 * 사용자 선택 정보를 메인으로 전달한다.
 * @param
 * @return
 */
scwin.btnCnfirm_onclick = function() {
	var jsonList = "";

	// 선택된 항목 받아오기
	if (scwin.popupParam.multiCheckYn == "Y") {
		jsonList = grdUsrList.getCheckedJSON("chk");
	} else {
		var focusedIndex = grdUsrList.getFocusedRowIndex();
		if (focusedIndex >= 0) {
			jsonList = dltUsrList.getRangeJSON(focusedIndex, focusedIndex);
		}
	}

	// 부모창으로 전달
	if (jsonList != undefined && jsonList != "") {
		/*
		if (utilLib.isNull(pparam)) {
			window.close();
		} else {
			WebSquare.util.closePopup( popupId );
		}
		*/
		comLib.closePopupCall($p, scwin.popupParam, true, jsonList);
	} else {
		// 선택된 자료가 없습니다.
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00258"));
	}
};

/**
 * 부서트리 선택시 해당 부서의 사원목록을 자동으로 조회한다.
 * @param
 * @return
 */
scwin.trvDeptInfo_onlabelclick = function(value, nodeElement, index) {
	// 최상위 트리는 별도 조회 안함 (데이터가 너무 많다)
	if (index > 1) {
		// 조회조건 DataCollection 초기화
		dmaSearchParam.undo();
		dmaSearchParam.set("usrDeptCd", value);

		// 조직도 Depth 세팅
		dmaSearchParam.set("orgchtDp", scwin.popupParam.orgchtDp);
		scwin.searchUsrList();
	}
};

/**
 * 조회조건에서 엔터로도 조회할 수 있도록 처리
 * @param
 * @return
 */
scwin.ibxSearchTxt_onkeydown = function(e) {
	if (e.keyCode == 13) {
		scwin.btnSearch_onclick();
	}
};

// 단건선택인 경우 더블클릭으로도 선택 가능토록 처리
scwin.grdUsrList_oncelldblclick = function(row, col) {
	if (scwin.popupParam.multiCheckYn != "Y") {
		scwin.btnCnfirm_onclick();
	}
};
